-- Use this only if you previously seeded demo users by inserting directly into auth.users.
-- It removes the broken auth rows so the demo users can be recreated through the real
-- Supabase Auth admin API via `npm run seed:auth-demo`.

delete from auth.identities
where user_id in (
  'a0000001-0000-0000-0000-000000000001',
  'a0000002-0000-0000-0000-000000000002',
  'a0000003-0000-0000-0000-000000000003',
  'a0000004-0000-0000-0000-000000000004',
  'a0000005-0000-0000-0000-000000000005',
  'a0000006-0000-0000-0000-000000000006',
  'a0000007-0000-0000-0000-000000000007'
);

delete from auth.users
where id in (
  'a0000001-0000-0000-0000-000000000001',
  'a0000002-0000-0000-0000-000000000002',
  'a0000003-0000-0000-0000-000000000003',
  'a0000004-0000-0000-0000-000000000004',
  'a0000005-0000-0000-0000-000000000005',
  'a0000006-0000-0000-0000-000000000006',
  'a0000007-0000-0000-0000-000000000007'
);
